$SERVER_B_IP = "your-server-b-ip"
$SSH_USER = "root"
$SSH_EXE = "ssh"
$SCP_EXE = "scp"
foreach ($p in @(
    "C:\Program Files\Git\usr\bin\ssh.exe",
    "C:\Program Files (x86)\Git\usr\bin\ssh.exe",
    "C:\Program Files\Git\usr\bin\ssh.exe",
    "C:\Users\Administrator\AppData\Local\Programs\Git\usr\bin\ssh.exe"
)) {
    if (Test-Path $p) {
        $SSH_EXE = $p
        $SCP_EXE = $p.Replace('\usr\bin\ssh.exe', '\usr\bin\scp.exe')
        break
    }
}
Write-Host "Generating and uploading docker-compose.yml..." -ForegroundColor Cyan
$tmpYml = Join-Path $env:TEMP "autocode-storage.yml"
$dockerCompose = [System.Text.Encoding]::UTF8.GetString([Convert]::FromBase64String(''))
[System.IO.File]::WriteAllText($tmpYml, $dockerCompose, (New-Object System.Text.UTF8Encoding($false)))
$target = "${SSH_USER}@${SERVER_B_IP}:/opt/autocode/storage/docker-compose.yml"
& $SCP_EXE -o StrictHostKeyChecking=no $tmpYml $target
if ($LASTEXITCODE -ne 0) { Write-Host "Upload failed" -ForegroundColor Red; exit 1 }

Write-Host "Deploying storage components..." -ForegroundColor Cyan
$hostArg = "${SSH_USER}@${SERVER_B_IP}"
$decodedSetup = [System.Text.Encoding]::UTF8.GetString([Convert]::FromBase64String(''))
& $SSH_EXE -o StrictHostKeyChecking=no $hostArg $decodedSetup

Remove-Item $tmpYml -Force -ErrorAction SilentlyContinue
if ($LASTEXITCODE -eq 0) { Write-Host "Done" -ForegroundColor Green } else { Write-Host "Failed" -ForegroundColor Red }
